mapper.select:
SELECT t.id, t.executed_at as executedAt, t.coin, t.market, t.side, t.quantity, CASE WHEN t.market = 'BTC' AND b.btc_price IS NOT NULL THEN CAST(CAST(REPLACE(t.price, ',', '') AS DOUBLE) * CAST(REPLACE(b.btc_price, ',', '') AS DOUBLE) AS CHAR) ELSE t.price END as price, CASE WHEN t.market = 'BTC' AND b.btc_price IS NOT NULL THEN CAST(CAST(REPLACE(t.total_amount, ',', '') AS DOUBLE) * CAST(REPLACE(b.btc_price, ',', '') AS DOUBLE) AS CHAR) ELSE t.total_amount END as totalAmount, CASE WHEN t.market = 'BTC' AND b.btc_price IS NOT NULL THEN CAST(CAST(REPLACE(t.fee, ',', '') AS DOUBLE) * CAST(REPLACE(b.btc_price, ',', '') AS DOUBLE) AS CHAR) ELSE t.fee END as fee, CASE WHEN t.market = 'BTC' AND b.btc_price IS NOT NULL THEN CAST(CAST(REPLACE(t.settlement_amount, ',', '') AS DOUBLE) * CAST(REPLACE(b.btc_price, ',', '') AS DOUBLE) AS CHAR) ELSE t.settlement_amount END as settlementAmount, t.ordered_at as orderedAt FROM trade_history t LEFT JOIN trade_btc_history b ON DATE_FORMAT(t.executed_at, '%Y-%m-%d') = b.ordered_at
AND executed_at >= #{startDate}
AND executed_at <= #{endDate}
AND coin = #{coin}
AND side = #{side}
ORDER BY executed_at DESC
LIMIT #{limit} OFFSET #{offset}

